#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
    int i, j, tx;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            shadow[i][tx] = m[(offset + i) * matrix_dim + offset + tx];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx][i] -= shadow[tx][j] * shadow[j][i];
            }
            shadow[tx][i] /= shadow[i][i];
        }

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][tx] -= shadow[i + 1][j] * shadow[j][tx];
            }
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[(offset + i) * matrix_dim + offset + tx] = shadow[i][tx];
        }
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int b)
{
    int i, j, idx;
    int col_block_start = offset + (b + 1) * BLOCK_SIZE;
    int row_block_start = offset + (b + 1) * BLOCK_SIZE;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            dia[i][idx] = m[(offset + i) * matrix_dim + offset + idx];
            peri_row[i][idx] = m[(offset + i) * matrix_dim + col_block_start + idx];
            peri_col[i][idx] = m[(row_block_start + i) * matrix_dim + offset + idx];
        }
    }

    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i][idx] -= dia[i][j] * peri_row[j][idx];
            }
        }
    }

    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[idx][i] -= peri_col[idx][j] * dia[j][i];
            }
            peri_col[idx][i] /= dia[i][i];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[(offset + i) * matrix_dim + col_block_start + idx] = peri_row[i][idx];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[(row_block_start + i) * matrix_dim + offset + idx] = peri_col[i][idx];
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;
    int blocks;

    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int bx, by;
        blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        lud_diagonal_omp(m, matrix_dim, i);

#pragma omp parallel for private(bx) schedule(static) num_threads(omp_num_threads)
        for (bx = 0; bx < blocks; bx++) {
            lud_perimeter_block_omp(m, matrix_dim, i, bx);
        }

#pragma omp parallel for collapse(2) private(by, bx) schedule(static) num_threads(omp_num_threads)
        for (by = 0; by < blocks; by++) {
            for (bx = 0; bx < blocks; bx++) {
                int ty, tx, k;
                int global_row_id = i + (by + 1) * BLOCK_SIZE;
                int global_col_id = i + (bx + 1) * BLOCK_SIZE;
                float peri_row[BLOCK_SIZE][BLOCK_SIZE];
                float peri_col[BLOCK_SIZE][BLOCK_SIZE];

                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        peri_row[ty][tx] = m[(i + ty) * matrix_dim + global_col_id + tx];
                        peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + i + tx];
                    }
                }

                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        float sum = 0.0f;
                        for (k = 0; k < BLOCK_SIZE; k++) {
                            sum += peri_col[ty][k] * peri_row[k][tx];
                        }
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
